begin;
insert into public.feature_flags(key,enabled,description)values('partner_perks',false,'Curated partner benefits with controlled single-use redemption')on conflict(key)do nothing;
create table public.partners(id uuid primary key default gen_random_uuid(),slug text not null unique check(slug~'^[a-z0-9]+(?:-[a-z0-9]+)*$'),name text not null check(char_length(name)between 2 and 120),description text not null check(char_length(description)between 20 and 1500),website_url text check(website_url is null or website_url~'^https://'),logo_url text check(logo_url is null or logo_url~'^https://'),category text not null check(char_length(category)between 2 and 80),city text,country text not null default'Kenya',status text not null default'draft'check(status in('draft','active','archived')),created_by uuid not null references auth.users(id)on delete restrict,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.partner_perks(id uuid primary key default gen_random_uuid(),partner_id uuid not null references public.partners(id)on delete restrict,slug text not null unique check(slug~'^[a-z0-9]+(?:-[a-z0-9]+)*$'),title text not null check(char_length(title)between 3 and 160),description text not null check(char_length(description)between 20 and 1500),terms text not null check(char_length(terms)between 10 and 2000),inventory_total integer check(inventory_total is null or inventory_total>0),per_member_limit integer not null default 1 check(per_member_limit between 1 and 10),reservation_days integer not null default 7 check(reservation_days between 1 and 30),starts_at timestamptz not null,ends_at timestamptz not null,status text not null default'draft'check(status in('draft','published','paused','ended')),created_by uuid not null references auth.users(id)on delete restrict,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(ends_at>starts_at));
create table public.perk_redemptions(id uuid primary key default gen_random_uuid(),perk_id uuid not null references public.partner_perks(id)on delete restrict,user_id uuid not null references auth.users(id)on delete restrict,redemption_code text not null unique,status text not null default'reserved'check(status in('reserved','redeemed','cancelled','expired')),reserved_at timestamptz not null default now(),expires_at timestamptz not null,redeemed_at timestamptz,cancelled_at timestamptz,reviewed_by uuid references auth.users(id)on delete restrict,review_note text check(review_note is null or char_length(review_note)<=1000),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(expires_at>reserved_at));
create index partner_perks_catalog_idx on public.partner_perks(status,starts_at,ends_at);create index perk_redemptions_perk_idx on public.perk_redemptions(perk_id,status);create index perk_redemptions_user_idx on public.perk_redemptions(user_id,created_at desc);create unique index perk_active_reservation_idx on public.perk_redemptions(perk_id,user_id)where status='reserved';
alter table public.partners enable row level security;alter table public.partner_perks enable row level security;alter table public.perk_redemptions enable row level security;
create or replace function public.partner_perks_enabled()returns boolean language sql stable security definer set search_path=''as $$select coalesce((select enabled from public.feature_flags where key='partner_perks'),false)$$;
create policy "Members read active partners"on public.partners for select to authenticated using((public.partner_perks_enabled()and status='active'and public.is_active_member(auth.uid()))or public.is_admin(array['super_admin']::public.app_role[]));
create policy "Members read published perks"on public.partner_perks for select to authenticated using((public.partner_perks_enabled()and status='published'and starts_at<=now()and ends_at>now()and public.is_active_member(auth.uid()))or public.is_admin(array['super_admin']::public.app_role[]));
create policy "Members read own perk redemptions"on public.perk_redemptions for select to authenticated using(user_id=auth.uid()or public.is_admin(array['super_admin']::public.app_role[]));
create or replace function public.save_partner(p_partner_id uuid,p_slug text,p_name text,p_description text,p_website_url text,p_logo_url text,p_category text,p_city text,p_country text,p_status text)returns uuid language plpgsql security definer set search_path=''as $$declare saved uuid:=p_partner_id;begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;if p_status not in('draft','active','archived')then raise exception'Invalid partner status';end if;if p_partner_id is null then insert into public.partners(slug,name,description,website_url,logo_url,category,city,country,status,created_by)values(lower(trim(p_slug)),trim(p_name),trim(p_description),nullif(trim(p_website_url),''),nullif(trim(p_logo_url),''),trim(p_category),nullif(trim(p_city),''),coalesce(nullif(trim(p_country),''),'Kenya'),p_status,auth.uid())returning id into saved;else update public.partners set slug=lower(trim(p_slug)),name=trim(p_name),description=trim(p_description),website_url=nullif(trim(p_website_url),''),logo_url=nullif(trim(p_logo_url),''),category=trim(p_category),city=nullif(trim(p_city),''),country=coalesce(nullif(trim(p_country),''),'Kenya'),status=p_status,updated_at=now()where id=p_partner_id;if not found then raise exception'Partner not found';end if;end if;insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),'perk.partner_saved','partner',saved,jsonb_build_object('status',p_status));return saved;end;$$;
create or replace function public.save_partner_perk(p_perk_id uuid,p_partner_id uuid,p_slug text,p_title text,p_description text,p_terms text,p_inventory integer,p_member_limit integer,p_reservation_days integer,p_starts_at timestamptz,p_ends_at timestamptz,p_status text)returns uuid language plpgsql security definer set search_path=''as $$declare saved uuid:=p_perk_id;begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;if p_status not in('draft','published','paused','ended')or p_ends_at<=p_starts_at then raise exception'Invalid perk configuration';end if;if not exists(select 1 from public.partners where id=p_partner_id and status<>'archived')then raise exception'Active partner record required';end if;if p_perk_id is null then insert into public.partner_perks(partner_id,slug,title,description,terms,inventory_total,per_member_limit,reservation_days,starts_at,ends_at,status,created_by)values(p_partner_id,lower(trim(p_slug)),trim(p_title),trim(p_description),trim(p_terms),p_inventory,p_member_limit,p_reservation_days,p_starts_at,p_ends_at,p_status,auth.uid())returning id into saved;else update public.partner_perks set partner_id=p_partner_id,slug=lower(trim(p_slug)),title=trim(p_title),description=trim(p_description),terms=trim(p_terms),inventory_total=p_inventory,per_member_limit=p_member_limit,reservation_days=p_reservation_days,starts_at=p_starts_at,ends_at=p_ends_at,status=p_status,updated_at=now()where id=p_perk_id;if not found then raise exception'Perk not found';end if;end if;insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),'perk.offer_saved','partner_perk',saved,jsonb_build_object('status',p_status,'inventory',p_inventory));return saved;end;$$;
create or replace function public.list_partner_perks()returns table(perk_id uuid,slug text,title text,description text,terms text,partner_id uuid,partner_name text,partner_description text,partner_website text,partner_logo text,category text,city text,country text,inventory_total integer,inventory_remaining bigint,per_member_limit integer,starts_at timestamptz,ends_at timestamptz,status text,own_redemption_id uuid,own_redemption_code text,own_redemption_status text,own_expires_at timestamptz)language plpgsql stable security definer set search_path=''as $$begin if auth.uid()is null then raise exception'Authentication required';end if;if not public.partner_perks_enabled()and not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Partner perks are not available yet';end if;return query select k.id,k.slug,k.title,k.description,k.terms,p.id,p.name,p.description,p.website_url,p.logo_url,p.category,p.city,p.country,k.inventory_total,case when k.inventory_total is null then null else greatest(k.inventory_total-(select count(*)from public.perk_redemptions x where x.perk_id=k.id and x.status in('reserved','redeemed')),0)end,k.per_member_limit,k.starts_at,k.ends_at,k.status,r.id,r.redemption_code,r.status,r.expires_at from public.partner_perks k join public.partners p on p.id=k.partner_id left join lateral(select x.*from public.perk_redemptions x where x.perk_id=k.id and x.user_id=auth.uid()and x.status in('reserved','redeemed')order by x.created_at desc limit 1)r on true where(k.status='published'and p.status='active'and k.starts_at<=now()and k.ends_at>now())or public.is_admin(array['super_admin']::public.app_role[])order by k.starts_at desc;end;$$;
create or replace function public.reserve_partner_perk(p_perk_id uuid)returns table(redemption_id uuid,redemption_code text,expires_at timestamptz)language plpgsql security definer set search_path=''as $$declare target public.partner_perks%rowtype;used integer;member_used integer;saved public.perk_redemptions%rowtype;begin if not public.partner_perks_enabled()or not public.is_active_member(auth.uid())then raise exception'Active member access required';end if;select*into target from public.partner_perks where id=p_perk_id for update;if not found or target.status<>'published'or target.starts_at>now()or target.ends_at<=now()then raise exception'This perk is not available';end if;select count(*)into member_used from public.perk_redemptions where perk_id=p_perk_id and user_id=auth.uid()and status in('reserved','redeemed');if member_used>=target.per_member_limit then raise exception'Member redemption limit reached';end if;select count(*)into used from public.perk_redemptions where perk_id=p_perk_id and status in('reserved','redeemed');if target.inventory_total is not null and used>=target.inventory_total then raise exception'This perk is fully reserved';end if;insert into public.perk_redemptions(perk_id,user_id,redemption_code,expires_at)values(p_perk_id,auth.uid(),'HAT-'||upper(substr(replace(gen_random_uuid()::text,'-',''),1,10)),least(target.ends_at,now()+make_interval(days=>target.reservation_days)))returning*into saved;perform public.enqueue_notification(auth.uid(),'network','Partner perk reserved','Your private redemption code is ready. Present it before the reservation expires.','/perks','perk-reserved:'||saved.id);insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),'perk.reserved','perk_redemption',saved.id,jsonb_build_object('perk_id',p_perk_id));return query select saved.id,saved.redemption_code,saved.expires_at;end;$$;
create or replace function public.review_perk_redemption(p_redemption_id uuid,p_action text,p_note text)returns void language plpgsql security definer set search_path=''as $$declare target public.perk_redemptions%rowtype;begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;if p_action not in('redeem','cancel')then raise exception'Unsupported action';end if;select*into target from public.perk_redemptions where id=p_redemption_id for update;if not found or target.status<>'reserved'then raise exception'Active reservation required';end if;if p_action='redeem'and target.expires_at<=now()then raise exception'Reservation has expired';end if;update public.perk_redemptions set status=case when p_action='redeem'then'redeemed'else'cancelled'end,redeemed_at=case when p_action='redeem'then now()end,cancelled_at=case when p_action='cancel'then now()end,reviewed_by=auth.uid(),review_note=nullif(trim(p_note),''),updated_at=now()where id=p_redemption_id;perform public.enqueue_notification(target.user_id,'network',case when p_action='redeem'then'Perk redeemed'else'Perk reservation cancelled'end,case when p_action='redeem'then'Your partner benefit has been marked as redeemed.'else'Your reservation was cancelled. Contact support if this was unexpected.'end,'/perks','perk-'||p_action||':'||target.id);insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),'perk.'||p_action,'perk_redemption',target.id,jsonb_build_object('note',nullif(trim(p_note),'')));end;$$;
create or replace function public.expire_perk_redemptions()returns integer language plpgsql security definer set search_path=''as $$declare changed integer;begin if coalesce(auth.jwt()->>'role','')<>'service_role'and not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Service or Super Admin required';end if;with x as(update public.perk_redemptions set status='expired',updated_at=now()where status='reserved'and expires_at<=now()returning 1)select count(*)into changed from x;insert into public.audit_events(actor_id,action,target_type,metadata)values(auth.uid(),'perk.expired_reconciled','perk_redemptions',jsonb_build_object('count',changed));return changed;end;$$;
create or replace function public.list_perk_redemptions_admin()returns table(redemption_id uuid,redemption_code text,perk_id uuid,perk_title text,partner_name text,user_id uuid,email text,display_name text,is_test_account boolean,status text,reserved_at timestamptz,expires_at timestamptz,redeemed_at timestamptz,review_note text)language plpgsql stable security definer set search_path=''as $$begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;return query select r.id,r.redemption_code,r.perk_id,k.title,p.name,r.user_id,u.email::text,pr.display_name,pr.is_test_account,r.status,r.reserved_at,r.expires_at,r.redeemed_at,r.review_note from public.perk_redemptions r join public.partner_perks k on k.id=r.perk_id join public.partners p on p.id=k.partner_id join auth.users u on u.id=r.user_id join public.profiles pr on pr.id=r.user_id order by r.created_at desc;end;$$;
revoke all on function public.partner_perks_enabled()from public;grant execute on function public.partner_perks_enabled()to authenticated;revoke all on function public.save_partner(uuid,text,text,text,text,text,text,text,text,text)from public;grant execute on function public.save_partner(uuid,text,text,text,text,text,text,text,text,text)to authenticated;revoke all on function public.save_partner_perk(uuid,uuid,text,text,text,text,integer,integer,integer,timestamptz,timestamptz,text)from public;grant execute on function public.save_partner_perk(uuid,uuid,text,text,text,text,integer,integer,integer,timestamptz,timestamptz,text)to authenticated;revoke all on function public.list_partner_perks()from public;grant execute on function public.list_partner_perks()to authenticated;revoke all on function public.reserve_partner_perk(uuid)from public;grant execute on function public.reserve_partner_perk(uuid)to authenticated;revoke all on function public.review_perk_redemption(uuid,text,text)from public;grant execute on function public.review_perk_redemption(uuid,text,text)to authenticated;revoke all on function public.expire_perk_redemptions()from public;grant execute on function public.expire_perk_redemptions()to authenticated,service_role;revoke all on function public.list_perk_redemptions_admin()from public;grant execute on function public.list_perk_redemptions_admin()to authenticated;
comment on table public.perk_redemptions is'Single-use member reservations; codes are private to the member and Super Admin operations.';
commit;
